VALUES
  ('social-worker-moex-08190', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '對許多社會工作實務的研究而言，依據隨機分派取得對照組較有實際上的困難，然而基於研究的效度考量， 下列敘述何者是正確的態度與作法？', '["社會工作應避免實驗研究，以免只得到無效的結論", "社會工作應放棄實驗研究，以免動輒觸犯研究倫理", "可以謹慎設計嘗試能獲得合理的內在效度的準實驗方法", "只能使用非實驗方法"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08191', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '針對同理心概念的測量，以同不同意10個關於同理心的敘述問項來測量同理心的程度，這是一種：', '["概念化", "操作化", "假設推衍", "理論建構"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08192', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '考生入學測驗的成績和其入學後的學業表現有高度的關聯性，表示入學測驗具有何種效度？', '["表面效度", "一致效度", "預測效度", "建構效度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08193', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '針對同理心概念的測量，研究者建構了一組包含10個問項的量表，每個問項都採正向的敘述，並以五點尺 度計分，例如：「非常同意」到「非常不同意」。蒐集資料後進行項目分析時，下列情形何者是具有 信度的指標？', '["各問項間都有正相關", "各問項間有些呈現正相關，有些則是負相關", "各問項之間至少應有零相關者", "問項間完全相關是最好的情況"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08194', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '調查青少年的偏差行為，下列何者是為了避免測量偏差（measurement bias），研究者在問卷設計上最應注 意的事項？', '["各種行為的敘述不宜出現有偏差意涵的用詞", "注意青少年的定義", "要問及行為發生的年齡", "要問及行為發生的頻度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08195', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '學科測驗成績的級分數，是屬於那一種測量尺度？', '["名目尺度", "順序尺度", "等距尺度", "等比尺度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08196', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列關於單案研究的敘述，何者不正確？', '["單案研究具有高的外在效度與內在效度", "機構或服務方案的評鑑也是一種單案研究", "巴洛夫（Pavlov）對狗進行的刺激反應學習行為的研究為一種單案研究", "特別適合社工實務工作者在臨床工作中使用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
