  ('social-worker-moex-08198', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究生終於決定了他的研究論文題目為：不同受暴經驗婦女的婚姻觀差異。請問下列何者正確？', '["自變項為婦女，依變項為婚姻觀", "自變項為婚姻觀，依變項為受暴經驗", "自變項為受暴經驗，依變項為婚姻觀", "自變項為婦女，依變項為受暴經驗"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-08199', 'social-worker', 'social-worker-moex-098-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '根據一項老人調查，發現都市的老人健康自評的滿意度較高，非都市的老人生活滿意度較高。請問這個研 究的自變項是什麼？', '["老人", "城鄉", "健康滿意度", "生活滿意度"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:41+00:00", "source_pdf_sha1": "cac5bed79b4c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "098160", "c": "902", "s": "7001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "098", "exam_name": "098年專技高考律師、會計師、社工師、不動產估價師、專利師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
